using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF9 renamed the discriminator JSON property from "Discriminator" to "$type".
            // Preserve the old name so existing documents remain queryable.
            entity.HasDiscriminator<string>("Discriminator");

            // EF9 removed the discriminator prefix from the JSON id property.
            // Existing docs use "Product|123" format — keep that so point-reads still work.
            entity.HasDiscriminatorInJsonId();

            // EF9 maps the key directly to the JSON "id" field and drops the shadow __id.
            // Existing docs store Id as a separate JSON property; preserve that with a shadow id.
            entity.HasShadowId();
        });

        // HasIndex removed — EF9 Cosmos provider throws instead of silently ignoring it.
        // Cosmos indexes all properties by default; manage custom policies via the Azure Portal.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

